// A Java program for Floyd Warshall All Pairs Shortest
// Path algorithm.
import java.lang.*;


public class AllPairShortestPath
{
    final static int INF = 99999, V = 4;

    void floydWarshall(int graph[][])
    {
        int dist[][] = new int[V][V];
        int i, j, k;

        /* Initialize the solution matrix same as input graph matrix.
           Or we can say the initial values of shortest distances
           are based on shortest paths considering no intermediate
           vertex. */
        for (i = 0; i < V; i++)
            for (j = 0; j < V; j++)
                dist[i][j] = graph[i][j];

        /* Add all vertices one by one to the set of intermediate
           vertices.
          ---> Before start of a iteration, we have shortest
               distances between all pairs of vertices such that
               the shortest distances consider only the vertices in
               set {0, 1, 2, .. k-1} as intermediate vertices.
          ----> After the end of a iteration, vertex no. k is added
                to the set of intermediate vertices and the set
                becomes {0, 1, 2, .. k} */
        for (k = 0; k < V; k++)
        {
            // Pick all vertices as source one by one
            for (i = 0; i < V; i++)
            {
                // Pick all vertices as destination for the
                // above picked source
                for (j = 0; j < V; j++)
                {
                    // If vertex k is on the shortest path from
                    // i to j, then update the value of dist[i][j]
                    if (dist[i][k] + dist[k][j] < dist[i][j])
                        dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Print the shortest distance matrix
        printSolution(dist);
    }

    void printSolution(int dist[][])
    {
        System.out.println("Following matrix shows the shortest "+
                         "distances between every pair of vertices");
        for (int i=0; i<V; ++i)
        {
            for (int j=0; j<V; ++j)
            {
                if (dist[i][j]==INF)
                    System.out.print("INF ");
                else
                    System.out.print(dist[i][j]+"   ");
            }
            System.out.println();
        }
    }

    // Driver program to test above function
    public static void main (String[] args)
    {
        /* Let us create the following weighted graph
           10
        (0)------->(3)
        |         /|\
        5 |          |
        |          | 1
        \|/         |
        (1)------->(2)
           3           */
        int graph[][] = { {0,   5,  INF, 10},
                          {INF, 0,   3, INF},
                          {INF, INF, 0,   1},
                          {INF, INF, INF, 0}
                        };
        AllPairShortestPath a = new AllPairShortestPath();

        // Print the solution
        a.floydWarshall(graph);
    }
}

public class FloydWarshall {
    public static double[][] floydWarshall(Object[][] distanceMatrix) {
        int n = distanceMatrix.length;
        double[][] dist = new double[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                dist[i][j] = toDistance(distanceMatrix[i][j]);
            }
        }

        for (int k = 0; k < n; k++) {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    double via = dist[i][k] + dist[k][j];
                    if (via < dist[i][j]) {
                        dist[i][j] = via;
                    }
                }
            }
        }
        return dist;
    }

    private static double toDistance(Object value) {
        if (value instanceof Number) {
            return ((Number) value).doubleValue();
        }
        if ("Infinity".equals(String.valueOf(value))) {
            return Double.POSITIVE_INFINITY;
        }
        if ("-Infinity".equals(String.valueOf(value))) {
            return Double.NEGATIVE_INFINITY;
        }
        return Double.parseDouble(String.valueOf(value));
    }
}

/**
 * Floyd-Warshall algorithm to find shortest paths between all pairs of vertices.
 * Input: distance matrix (2D array).
 * Returns the shortest distance matrix.
 */
fun floydWarshall(matrix: Array<DoubleArray>): Array<DoubleArray> {
    val n = matrix.size
    val dist = Array(n) { i -> matrix[i].copyOf() }

    for (k in 0 until n) {
        for (i in 0 until n) {
            for (j in 0 until n) {
                if (dist[i][k] != Double.POSITIVE_INFINITY &&
                    dist[k][j] != Double.POSITIVE_INFINITY &&
                    dist[i][k] + dist[k][j] < dist[i][j]
                ) {
                    dist[i][j] = dist[i][k] + dist[k][j]
                }
            }
        }
    }

    return dist
}

fun main() {
    val inf = Double.POSITIVE_INFINITY
    val matrix = arrayOf(
        doubleArrayOf(0.0, 3.0, inf, 7.0),
        doubleArrayOf(8.0, 0.0, 2.0, inf),
        doubleArrayOf(5.0, inf, 0.0, 1.0),
        doubleArrayOf(2.0, inf, inf, 0.0)
    )

    val result = floydWarshall(matrix)

    println("Shortest distance matrix:")
    for (row in result) {
        println(row.joinToString("\t") { if (it == inf) "INF" else it.toInt().toString() })
    }
}

